        flex-direction: column;
        padding: 2rem 1rem;
        border-top: 1px solid var(--border);
        transition: left var(--transition);
        z-index: 999;
        max-height: calc(100vh - 60px);
        overflow-y: auto;
    }

    .nav-menu.active {
        left: 0;
    }

    .nav-link {
        width: 100%;
        justify-content: flex-start;
        padding: 1rem;
        border-radius: 8px;
        margin-bottom: 0.5rem;
    }

    .menu-toggle {
        display: flex;
    }

    .main-content {
        margin-top: 60px;
    }

    .hero-section {
        min-height: auto;
        padding: 2rem 0;
    }

    .hero-container {
        padding: 0 1rem;
        gap: 2rem;
    }

    .hero-name {
        font-size: 2rem;
        margin-bottom: 1rem;
    }

    .hero-title {
        font-size: 1.2rem;
        margin-bottom: 1rem;
    }

    .hero-description {
        font-size: 1rem;
        margin-bottom: 2rem;
    }

    .hero-buttons {
        flex-direction: column;
        gap: 1rem;
        margin-bottom: 2rem;
    }

    .btn {
        width: 100%;
        justify-content: center;
        padding: 0.9rem 1.5rem;
    }

    .hero-social {
        justify-content: center;
        flex-wrap: wrap;
        gap: 1rem;
    }

    .social-icon {
        width: 45px;
        height: 45px;
    }

    .section {
        padding: 2rem 0;
    }

    .section-container {
        padding: 0 1rem;
    }

    .section-header {
        flex-wrap: wrap;
        gap: 1rem;
        margin-bottom: 2rem;
    }

    .section-number {
        font-size: 1.2rem;
    }

    .section-title {
        font-size: 1.8rem;
        flex-wrap: wrap;
    }

    .section-line {
        width: 100%;
        margin-inline-start: 0;
        margin-top: 0.5rem;
    }

    .about-stats {
        grid-template-columns: 1fr;
        gap: 1rem;
    }

    .stat-item {
        padding: 1.5rem;
    }

    .stat-number {
        font-size: 2rem;
    }

    .code-block {
        padding: 1.5rem;
        font-size: 0.8rem;
    }

    .skills-grid {
        grid-template-columns: 1fr;
        gap: 2rem;
    }

    .skill-category {
        padding: 2rem;
    }

    .category-title {
        font-size: 1.3rem;
        margin-bottom: 1.5rem;
    }

    .timeline {
        padding-inline-start: 1.5rem;
    }

    .timeline-item {
        padding-inline-start: 2rem;
        padding-bottom: 3rem;
    }

    .timeline-marker {
        left: -1.75rem;
        width: 14px;
        height: 14px;
    }

    .timeline-content {
        padding: 1.5rem;
    }

    .timeline-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 0.5rem;
    }

    .timeline-title {
        font-size: 1.3rem;
    }

    .timeline-achievements {
        padding: 1rem;
        gap: 0.6rem;
    }

    .achievement-item {
        font-size: 0.9rem;
    }

    .projects-grid {
        grid-template-columns: 1fr;
        gap: 2rem;
    }

    .project-content {
        padding: 2rem;
    }

    .project-title {
        font-size: 1.3rem;
    }

    .contact-content {
        gap: 2rem;
    }

    .contact-item {
        padding: 1.5rem;
        flex-direction: column;
        text-align: center;
        gap: 1rem;
    }

    .contact-icon {
        width: 50px;
        height: 50px;
        font-size: 1.2rem;
        margin: 0 auto;
    }

    .contact-form {
        gap: 1.5rem;
    }

    .form-input {
        padding: 0.9rem;
        font-size: 0.95rem;
    }

    .footer-container {
        padding: 0 1rem;
    }

    .footer-content {
        flex-direction: column;
        gap: 1.5rem;
        text-align: center;
    }

    .footer-text-wrapper {
        text-align: center;
    }

    .footer-text {
        justify-content: center;
        font-size: 0.85rem;
    }

    .footer-author {
        justify-content: center;
        font-size: 0.85rem;
    }

    .footer-social {
        justify-content: center;
        gap: 1rem;
    }

    .hero-image-container {
        width: 280px;
        height: 280px;
    }

    .floating-badge {
        display: none;
    }

    .scroll-indicator {
        bottom: 1rem;
    }
}

