    }

    .footer-text {
        justify-content: center;
        font-size: 0.85rem;
    }

    .footer-author {
        justify-content: center;
        font-size: 0.85rem;
    }

    .footer-social {
        justify-content: center;
        gap: 1rem;
    }

    .hero-image-container {
        width: 280px;
        height: 280px;
    }

    .floating-badge {
        display: none;
    }

    .scroll-indicator {
        bottom: 1rem;
    }
}

@media (max-width: 375px) {
    html {
        font-size: 12px;
    }

    .nav-container {
        padding: 0.6rem 0.7rem;
    }

