    }

    .skill-category {
        padding: 1.2rem;
    }

    .category-title {
        font-size: 1.1rem;
        margin-bottom: 0.8rem;
    }

    .timeline {
        padding-inline-start: 0.8rem;
    }

    .timeline-item {
        padding-inline-start: 1.2rem;
        padding-bottom: 2rem;
    }

    .timeline-marker {
        left: -1rem;
        width: 10px;
        height: 10px;
    }

    .timeline-content {
        padding: 1rem;
    }

    .timeline-title {
        font-size: 1.1rem;
    }

    .project-content {
        padding: 1.2rem;
    }

    .project-title {
        font-size: 1.1rem;
    }

    .contact-item {
        padding: 1rem;
    }

    .footer-text {
        font-size: 0.75rem;
        flex-direction: column;
        gap: 0.3rem;
    }

    .footer-divider {
        display: none;
    }

    .footer-author {
        font-size: 0.75rem;
        flex-direction: column;
        gap: 0.3rem;
    }

    .footer-social-link {
        width: 35px;
        height: 35px;
    }

