        gap: 0.6rem;
    }

    .tool-card {
        padding: 1rem 0.4rem;
    }

    .tool-card img {
        width: 35px;
        height: 35px;
    }

    .tool-card span {
        font-size: 0.7rem;
    }

    .skw-grid {
        grid-template-columns: 1fr;
        gap: 0;
    }

    .skw-box {
        margin: 10px 0;
        height: auto;
        min-height: 250px;
    }

    .skw-content {
        padding: 18px 16px;
    }

    .gc-card-inner {
